import os, json, re, urllib.parse, xml.etree.ElementTree as ET
workspace = "/workspace/scaa_recon"
katana_file = os.path.join(workspace, "katana.jsonl")
http_root_file = os.path.join(workspace, "http_root.html")
https_root_file = os.path.join(workspace, "https_root.html")
http_headers_http = os.path.join(workspace, "http_headers_http.txt")
http_headers_https = os.path.join(workspace, "http_headers_https.txt")
nmap_xml = os.path.join(workspace, "nmap_quick.xml")

endpoints = set()
hosts = set()
js_urls = set()
forms = set()
links = set()
headers_summary = {}
open_ports = []

def add_url(u):
    if not u:
        return
    u = u.strip()
    if u.endswith(","):
        u = u[:-1]
    endpoints.add(u)
    try:
        p = urllib.parse.urlparse(u)
        if p.netloc:
            hosts.add(p.netloc)
        if p.path.endswith(".js") or ".js?" in u:
            js_urls.add(u)
    except Exception:
        pass

# Parse katana JSONL if present
if os.path.exists(katana_file):
    with open(katana_file, "r", errors="ignore") as fh:
        for line in fh:
            line = line.strip()
            if not line:
                continue
            try:
                obj = json.loads(line)
            except Exception:
                # fallback: extract urls with regex
                for u in re.findall(r"https?://[^\s'\"<>]+", line):
                    add_url(u)
                continue
            if isinstance(obj, dict):
                if "url" in obj and isinstance(obj["url"], str):
                    add_url(obj["url"])
                for k, v in obj.items():
                    if isinstance(v, str) and (v.startswith("http://") or v.startswith("https://")):
                        add_url(v)
                    elif isinstance(v, list):
                        for item in v:
                            if isinstance(item, str) and (item.startswith("http://") or item.startswith("https://")):
                                add_url(item)

# Parse root HTML pages for scripts, forms, links
def normalize_relative(u):
    if u.startswith("//"):
        return "http:" + u
    if u.startswith("/"):
        return "http://scaa.us" + u
    if u.startswith("./") or not u.startswith("http"):
        return "http://scaa.us/" + u.lstrip("./")
    return u

for fpath in (http_root_file, https_root_file):
    if os.path.exists(fpath):
        with open(fpath, "r", errors="ignore") as fh:
            txt = fh.read()
            for m in re.findall(r'<script[^>]+src=["\\\']([^"\\\']+)["\\\']', txt, re.I):
                url = normalize_relative(m)
                add_url(url)
                js_urls.add(url)
            for m in re.findall(r'<link[^>]+href=["\\\']([^"\\\']+)["\\\']', txt, re.I):
                url = normalize_relative(m)
                add_url(url)
            for a in re.findall(r'<form[^>]+action=["\\\']([^"\\\']+)["\\\']', txt, re.I):
                url = normalize_relative(a)
                forms.add(url)
                add_url(url)
            for a in re.findall(r'href=["\\\'](https?://[^"\\\']+)["\\\']', txt, re.I):
                links.add(a)
                add_url(a)

# Parse headers
def parse_headers(path):
    if not os.path.exists(path):
        return {}
    out = {}
    with open(path, "r", errors="ignore") as fh:
        for line in fh:
            if ":" in line:
                k, v = line.split(":", 1)
                out[k.strip()] = v.strip()
    return out

headers_summary["http"] = parse_headers(http_headers_http)
headers_summary["https"] = parse_headers(http_headers_https)

# Parse nmap XML for open ports
if os.path.exists(nmap_xml):
    try:
        tree = ET.parse(nmap_xml)
        root = tree.getroot()
        for host in root.findall(".//host"):
            addr_elem = host.find("address")
            addr = addr_elem.get("addr") if addr_elem is not None else ""
            for port in host.findall(".//port"):
                state_elem = port.find("state")
                if state_elem is not None and state_elem.get("state") == "open":
                    portid = port.get("portid")
                    svc = ""
                    svc_elem = port.find("service")
                    if svc_elem is not None:
                        svc = svc_elem.get("name","")
                    try:
                        portnum = int(portid)
                    except Exception:
                        portnum = portid
                    open_ports.append({"addr": addr, "port": portnum, "service": svc})
    except Exception:
        pass

# Write artifacts
os.makedirs(workspace, exist_ok=True)
with open(os.path.join(workspace, "endpoints.txt"), "w") as fh:
    for u in sorted(endpoints):
        fh.write(u + "\n")
with open(os.path.join(workspace, "js_urls.txt"), "w") as fh:
    for u in sorted(js_urls):
        fh.write(u + "\n")
with open(os.path.join(workspace, "hosts.txt"), "w") as fh:
    for h in sorted(hosts):
        fh.write(h + "\n")
with open(os.path.join(workspace, "forms.txt"), "w") as fh:
    for f in sorted(forms):
        fh.write(f + "\n")
with open(os.path.join(workspace, "open_ports.json"), "w") as fh:
    json.dump(open_ports, fh, indent=2)
with open(os.path.join(workspace, "headers_summary.json"), "w") as fh:
    json.dump(headers_summary, fh, indent=2)

# Build prioritized next steps text
next_steps = []
next_steps.append("1) Web application testing (High priority):")
next_steps.append("   - Focus on HTTP(S) endpoints discovered (endpoints.txt). Test for SQLi on any POST/GET parameters, test for reflected/stored XSS in inputs and query parameters.")
next_steps.append("   - Test /admin, /login, /api, /uploads, /wp-admin, /users, /dashboard paths if present.")
next_steps.append("")
next_steps.append("2) Authorization and IDOR (High):")
next_steps.append("   - Enumerate object IDs (order_id, user_id) in API endpoints and attempt horizontal/vertical access checks.")
next_steps.append("")
next_steps.append("3) SSRF (Medium):")
next_steps.append("   - Look for server-side URL fetchers or preview endpoints. Use responses/timeouts to detect server-side fetch behaviour.")
next_steps.append("")
next_steps.append("4) File upload and content handling (Medium):")
next_steps.append("   - Identify file upload endpoints. Test content-type validation and verify that previews do not execute active content.")
next_steps.append("")
next_steps.append("5) Services exposed at network level (Critical to review):")
if open_ports:
    for p in open_ports:
        next_steps.append(f"   - Port {p['port']}/tcp ({p['service']}) is open on {p['addr']}. Evaluate whether service should be internet-exposed. Port 3306 (MySQL) exposure is high risk; consider blocking or allowlisting.")
else:
    next_steps.append("   - No open TCP service details available.")
next_steps.append("")
next_steps.append("Reproduction candidates (sample endpoints from endpoints.txt):")
count = 0
for u in sorted(endpoints):
    if count >= 20:
        break
    next_steps.append("  - " + u)
    count += 1

with open(os.path.join(workspace, "next_steps.txt"), "w") as fh:
    fh.write("\n".join(next_steps))

# Final summary print
print("Recon artifact summary:")
print(f"  endpoints: {len(endpoints)} (written to {workspace}/endpoints.txt)")
print(f"  js files: {len(js_urls)} (written to {workspace}/js_urls.txt)")
print(f"  hosts: {len(hosts)} (written to {workspace}/hosts.txt)")
print(f"  forms: {len(forms)} (written to {workspace}/forms.txt)")
print(f"  open ports: {len(open_ports)} (written to {workspace}/open_ports.json)")
print(f"  headers summary: {workspace}/headers_summary.json")
print(f"  next steps: {workspace}/next_steps.txt")

